Решение 2: пул предварительно распределённых буферов
Вместо того, чтобы распределять буферы по запросу, будем распределять пул заранее:
#define BUFFER_POOL_SIZE 2048

typedef struct {
 rx_buffer_t buffers[BUFFER_POOL_SIZE];
 rx_ring_t free_list; // Кольцевой буфер свободных буферов
} buffer_pool_t;

static buffer_pool_t g_buffer_pool;

void buffer_pool_init(buffer_pool_t *pool) {
 rx_ring_init(&pool->free_list);

 // Добавляем все буферы в список свободных
 for (int i = 0; i < BUFFER_POOL_SIZE; i++) {
 rx_ring_enqueue(&pool->free_list, &pool->buffers[i]);
 }
}

rx_buffer_t *buffer_alloc(buffer_pool_t *pool) {
 return rx_ring_dequeue(&pool->free_list);
}

void buffer_free(buffer_pool_t *pool, rx_buffer_t *buf) {
 rx_ring_enqueue(&pool->free_list, buf);
}
Преимущества
:
Отсутствие malloc в прерывании
: просто извлечение из свободного списка
Скорость
: распределение/освобождение за O(1)
Ограничение на размер занимаемой памяти
: фиксированный размер пула
Удобство для памяти
: буферы хранятся в памяти друг за другом
